import{_ as t,o,c as n,a3 as s}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"47A. Right To Disconnect","description":"","frontmatter":{"title":"47A. Right To Disconnect","eba":"Allied Health Professionals 2021-2026","topics":["leave","hours"]},"headers":[],"relativePath":"ebas/allied-health/hours-of-work/47A-right-to-disconnect.md","filePath":"ebas/allied-health/hours-of-work/47A-right-to-disconnect.md"}'),r={name:"ebas/allied-health/hours-of-work/47A-right-to-disconnect.md"};function a(i,e,c,h,l,p){return o(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="_47a-right-to-disconnect" tabindex="-1">47A. Right To Disconnect <a class="header-anchor" href="#_47a-right-to-disconnect" aria-label="Permalink to &quot;47A. Right To Disconnect&quot;">​</a></h1><p><strong>47A.1</strong> The Employer will respect an Employee’s’ periods of leave and rest days.</p><p><strong>47A.2</strong> Other than where reasonably necessary:</p><p><strong>(a)</strong> in emergency situations;</p><p><strong>(b)</strong> for genuine welfare matters;</p><p><strong>(c)</strong> to offer Employees additional hours;</p><p><strong>(d)</strong> in relation to a process under this Agreement; or</p><p><strong>(e)</strong> for any non-clinical matter that requires urgent attention; an Employee will not be contacted outside the Employee’s hours of work by the Employer or other employees for work purposes.</p><p><strong>47A.3</strong> The Employer will make other employees aware of the requirements of the Right to Disconnect clause 47A, and indicate to them that they are not to contact an Employee outside the Employee’s hours of work in circumstances other than those in subclause 47A.2</p><p><strong>47A.4</strong> Employees are:</p><p><strong>(a)</strong> entitled to disengage from forms of technology that have a connection to the workplace such as work phones, emails, chat groups and social media; and</p><p><strong>(b)</strong> not required to respond to emails, phone calls or any other form of communication (including chat groups and social media); outside of their hours of work, subject to subclause 47A.2.</p><p><strong>47A.5</strong> This clause 47A does not apply to any period where the Employee is in receipt of the on-call allowance in subclause 36.2.</p><p><strong>47A.6</strong> Raising Concerns</p><p><strong>(a)</strong> Where an Employee believes they are not able to disconnect, including where they are being contacted in circumstances other than those in subclause 47A.2, they should raise this with the Employer. Where this clause 47A is not being complied with, the Employer will rectify this.</p><p><strong>(b)</strong> Notwithstanding the above, the Employee may raise a dispute or grievance at any time.</p>',16)])])}const m=t(r,[["render",a]]);export{d as __pageData,m as default};
